#!/usr/bin/env node
/**
 * Generate the COMMITTED cross-feature import baseline (AE-0083).
 *
 * Reproducible command:
 *   npm run boundaries:baseline
 *
 * Writes `scripts/feature-boundary-baseline.json` capturing:
 *   - `count`: number of grandfathered cross-feature import edges (the ratchet
 *     ceiling — lint fails if violations exceed this)
 *   - `allowlist`: stable `<file>::<feature>` keys for each grandfathered edge
 *   - `violations`: human-readable detail for review/auditing
 *
 * This file is generated, never hand-edited. Re-run after Phase 7 refactors
 * remove violations to RATCHET THE COUNT DOWN (it must only ever shrink).
 */

import { writeFileSync } from "node:fs";

import { BASELINE_PATH } from "./feature-boundary.config.mjs";
import {
  scanCrossFeatureImports,
  violationKey,
} from "./feature-boundary-scan.mjs";

function main() {
  const violations = scanCrossFeatureImports();
  const allowlist = [...new Set(violations.map(violationKey))].sort();

  const baseline = {
    $comment:
      "GENERATED by scripts/generate-feature-boundary-baseline.mjs (npm run boundaries:baseline). Do not hand-edit. AE-0083 cross-feature import ratchet.",
    count: allowlist.length,
    allowlist,
    violations: violations.map((violation) => ({
      file: violation.file,
      to: violation.to,
      specifier: violation.specifier,
    })),
  };

  writeFileSync(BASELINE_PATH, `${JSON.stringify(baseline, null, 2)}\n`, "utf8");
  process.stdout.write(
    `Wrote ${BASELINE_PATH} with ${baseline.count} grandfathered cross-feature import(s).\n`,
  );
}

main();
